<template><BaseModal :model-value="modelValue" @update:modelValue="$emit('update:modelValue',$event)" title="Check IN"><form class="space-y-3" @submit.prevent="submit"><input type="date" v-model="form.date" class="input" required><TimeChipSelector v-model="form.time"/><select class="input" v-model="form.unit_id"><option v-for="r in rooms" :value="r.value" :key="r.value">{{ r.label }}</option></select><textarea class="input h-24" v-model="form.note" placeholder="Write any comment"></textarea><button class="btn-primary w-full">Check IN</button></form></BaseModal></template>
<script setup>import {reactive,watch} from 'vue'; import BaseModal from './BaseModal.vue'; import TimeChipSelector from './TimeChipSelector.vue'; const props=defineProps({modelValue:Boolean,rooms:Array,reservationId:Number,unitId:Number}); const emit=defineEmits(['update:modelValue','submitted']); const form=reactive({reservation_id:null,unit_id:null,date:new Date().toISOString().slice(0,10),time:'10:00 AM',note:''}); watch(()=>[props.reservationId,props.unitId],()=>{form.reservation_id=props.reservationId; form.unit_id=props.unitId;},{immediate:true}); const submit=()=>emit('submitted',{...form});</script>
